"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["8603"],{4398(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>d,frontMatter:()=>t,contentTitle:()=>r,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Planets & Points/Midheaven","title":"Midheaven","description":"Principle:","source":"@site/docs/Planets & Points/Midheaven.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Midheaven","permalink":"/Planets & Points/Midheaven","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Midheaven.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Mars","permalink":"/Planets & Points/Mars"},"next":{"title":"Moon","permalink":"/Planets & Points/Moon"}}'),a=i(4848),s=i(8453);let t={},r,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function p(e){let n={h3:"h3",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Ego-consciousness and spiritual awareness."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The individualised man, the aim of life."}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Ego-consciousness, the function of the brain proper."}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The individual."}),"\n",(0,a.jsx)(n.p,{children:"Position in the Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. The successful establishment of one's own individuality coupled with intense awareness of objectives in life, ambition, optimism, confidence, the desire to lead. \u2013 Fanaticism, rashness, covetousness."}),"\n",(0,a.jsx)(n.p,{children:"II. Persistent pursuit of one's aims, endurance, slow but sure establishment of one's own personality, the striving for secure circumstances in life, tolerance. \u2013 The tendency to be particular and difficult to please in one's desires, mistrust, egotism."}),"\n",(0,a.jsx)(n.p,{children:"III. Manifold aims, vigorous striving, periodic creativeness, quick but not always permanent establishment of one's own individuality. \u2013 The tendency to scatter one's energy, superficiality."}),"\n",(0,a.jsx)(n.p,{children:"IV. Tactful but emphatic establishment of one's individuality, the striving for independence in spite of great consideration for others, simplicity and modestness, thrift. \u2013 Impressionability, sensitiveness."}),"\n",(0,a.jsx)(n.p,{children:"V. High aspirations, a strong urge to climb socially, self-confidence, optimism, generosity, the urge to lead, organisation. \u2013 Egotism, a pretentious nature, hypersensitiveness in matters of honour."}),"\n",(0,a.jsx)(n.p,{children:"VI. The striving for a secure livelihood and a permanent position in life, advancement in life by simple means, organisation, tidiness, a critical attitude. \u2013 Petty criticism, susceptibility to flattery and unfounded praise, hypersensitiveness."}),"\n",(0,a.jsx)(n.p,{children:"VII. A harmonious person, advancement in career through reliance on others using their sponsorship, cooperation with others, success in life through sociable behaviour and through adaptation, strong material interests. \u2013 Exploitation of others, pleasant manners without sincerity."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Ambitious striving coupled with great endeavour and hard work, industry, perseverance, sympathetic understanding of others, the right grasp of every situation, a strong sense of acquisition. \u2013 Ruthlessness, overestimation of self, the habit of overtaxing one's powers and energy."}),"\n",(0,a.jsx)(n.p,{children:"IX. The striving for material security and for high standing, great planning-power, extension or enlargement in the sphere of thought, growth of the spiritual or inner side of one's nature. \u2013 Adventurous aspirations, a conservative attitude, the urge to be a person of importance or always to be in the limelight, inconstancy."}),"\n",(0,a.jsx)(n.p,{children:"X. Self-confidence, an intense striving for the attainment of one's objectives, slow but sure establishment of one's own personality through industry and endurance, simplicity and modestness, domesticity, a sense of reality. \u2013 Concentration upon oneself and upon one's work, a sober and prosaic nature, increasing loneliness."}),"\n",(0,a.jsx)(n.p,{children:"XI. New and modern aims and aspirations, periodic creativeness, occasional and sudden assertion of oneself, the grasping of the best possibilities, cooperation with others under one's own leadership. \u2013 A mania for innovations and novelties, a scattering of one's energies through too much planning."}),"\n",(0,a.jsx)(n.p,{children:"XII. A wait and see attitude, the striving for a simple and easy life with occasional pleasures and periodic seclusion in order to occupy oneself with philosophical problems. \u2013 A lack of clarity, impressionability, temporary instability."}),"\n",(0,a.jsx)(n.p,{children:"N.B."}),"\n",(0,a.jsx)(n.p,{children:'Compare the article by Dipl. Ing. SUEBKE in "Mensch im All" (X, 7) which has been partly utilised in the foregoing definitions.'}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"MEDIUM COELI (M.C.)"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"\u015Awiadomo\u015B\u0107 Ego i \u015Bwiadomo\u015B\u0107 duchowa."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Zindywidualizowany cz\u0142owiek, cel \u017Cycia."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"\u015Awiadomo\u015B\u0107 Ego, funkcja m\xf3zgu w\u0142a\u015Bciwego."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Jednostka."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Udane ugruntowanie w\u0142asnej indywidualno\u015Bci po\u0142\u0105czone z intensywn\u0105 \u015Bwiadomo\u015Bci\u0105 cel\xf3w \u017Cyciowych, ambicja, optymizm, pewno\u015B\u0107 siebie, pragnienie przewodzenia. \u2013 Fanatyzm, lekkomy\u015Blno\u015B\u0107, chciwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"II. Wytrwa\u0142e d\u0105\u017Cenie do w\u0142asnych cel\xf3w, wytrzyma\u0142o\u015B\u0107, powolne, lecz pewne ugruntowanie w\u0142asnej osobowo\u015Bci, d\u0105\u017Cenie do bezpiecznych warunk\xf3w \u017Cyciowych, tolerancja. \u2013 Tendencja do bycia wybrednym i trudnym do zadowolenia w swoich pragnieniach, nieufno\u015B\u0107, egotizm."}),"\n",(0,a.jsx)(n.p,{children:"III. R\xf3\u017Cnorodne cele, energiczne d\u0105\u017Cenie, okresowa kreatywno\u015B\u0107, szybkie, lecz nie zawsze trwa\u0142e ugruntowanie w\u0142asnej indywidualno\u015Bci. \u2013 Tendencja do rozpraszania swojej energii, powierzchowno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"IV. Taktowne, lecz stanowcze ugruntowanie w\u0142asnej indywidualno\u015Bci, d\u0105\u017Cenie do niezale\u017Cno\u015Bci pomimo wielkiego liczenia si\u0119 z innymi, prostota i skromno\u015B\u0107, oszcz\u0119dno\u015B\u0107. \u2013 Podatno\u015B\u0107 na wra\u017Cenia, wra\u017Cliwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"V. Wysokie aspiracje, silna potrzeba wspinania si\u0119 po szczeblach kariery spo\u0142ecznej, pewno\u015B\u0107 siebie, optymizm, wielkoduszno\u015B\u0107, pragnienie przewodzenia, organizacja. \u2013 Egotizm, pretensjonalna natura, nadwra\u017Cliwo\u015B\u0107 w kwestiach honoru."}),"\n",(0,a.jsx)(n.p,{children:"VI. D\u0105\u017Cenie do bezpiecznego utrzymania i sta\u0142ej pozycji w \u017Cyciu, awans w \u017Cyciu za pomoc\u0105 prostych \u015Brodk\xf3w, organizacja, porz\u0105dek, krytyczna postawa. \u2013 ma\u0142ostkowa krytyka, podatno\u015B\u0107 na pochlebstwa i bezpodstawne pochwa\u0142y, nadwra\u017Cliwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"VII. Harmonijna osoba, awans w karierze dzi\u0119ki poleganiu na innych przy wykorzystaniu ich protektoratu (sponsoringu), wsp\xf3\u0142praca z innymi, sukces w \u017Cyciu poprzez towarzyskie zachowanie i zdolno\u015B\u0107 adaptacji, silne interesy materialne. \u2013 Wyzyskiwanie innych, przyjemne maniery bez szczero\u015Bci."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Ambitne d\u0105\u017Cenie po\u0142\u0105czone z wielkim wysi\u0142kiem i ci\u0119\u017Ck\u0105 prac\u0105, pracowito\u015B\u0107, wytrwa\u0142o\u015B\u0107, pe\u0142ne empatii rozumienie innych, w\u0142a\u015Bciwe poj\u0119cie ka\u017Cdej sytuacji, silne poczucie zdobywania. \u2013 Bezwzgl\u0119dno\u015B\u0107, przecenianie samego siebie, nawyk nadwyr\u0119\u017Cania swoich si\u0142 i energii."}),"\n",(0,a.jsx)(n.p,{children:"IX. D\u0105\u017Cenie do bezpiecze\u0144stwa materialnego i wysokiej pozycji, wielka zdolno\u015B\u0107 planowania, rozszerzenie lub powi\u0119kszenie w sferze my\u015Bli, wzrost duchowej lub wewn\u0119trznej strony w\u0142asnej natury. \u2013 Aspiracje pe\u0142ne przyg\xf3d, konserwatywna postawa, potrzeba bycia osob\u0105 wa\u017Cn\u0105 lub bycia zawsze w centrum uwagi, niesta\u0142o\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"X. Pewno\u015B\u0107 siebie, intensywne d\u0105\u017Cenie do osi\u0105gni\u0119cia w\u0142asnych cel\xf3w, powolne, lecz pewne ugruntowanie w\u0142asnej osobowo\u015Bci poprzez pracowito\u015B\u0107 i wytrwa\u0142o\u015B\u0107, prostota i skromno\u015B\u0107, przywi\u0105zanie do ogniska domowego, poczucie rzeczywisto\u015Bci. \u2013 Koncentracja na sobie i na swojej pracy, trze\u017Awa i prozaiczna natura, rosn\u0105ca samotno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"XI. Nowe i nowoczesne cele oraz aspiracje, okresowa kreatywno\u015B\u0107, okazjonalne i nag\u0142e wyra\u017Canie (przeforsowywanie) siebie, chwytanie najlepszych mo\u017Cliwo\u015Bci, wsp\xf3\u0142praca z innymi pod w\u0142asnym przewodnictwem. \u2013 Mania na punkcie innowacji i nowo\u015Bci, rozpraszanie swoich energii z powodu zbyt wielkiej ilo\u015Bci plan\xf3w."}),"\n",(0,a.jsx)(n.p,{children:"XII. Postawa wyczekuj\u0105ca, d\u0105\u017Cenie do prostego i \u0142atwego \u017Cycia z okazjonalnymi przyjemno\u015Bciami i okresowym odosobnieniem w celu zajmowania si\u0119 problemami filozoficznymi. \u2013 Brak jasno\u015Bci, podatno\u015B\u0107 na wra\u017Cenia, chwilowa niestabilno\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"N.B. (Uwaga)"}),"\n",(0,a.jsx)(n.p,{children:"Por\xf3wnaj artyku\u0142 dypl. in\u017C. SUEBKE w \u201EMensch im All\u201D (X, 7), kt\xf3ry zosta\u0142 cz\u0119\u015Bciowo wykorzystany w powy\u017Cszych definicjach."})]})}function d(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(p,{...e})}):p(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>r});var o=i(6540);let a={},s=o.createContext(a);function t(e){let n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:t(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);